from typing import Optional
from pydantic import BaseModel
from functools import wraps

# Define which fields are safe to expose per task context
DATA_SCHEMAS = {
    "billing_inquiry": {
        "allowed_fields": {"order_id", "order_status", "order_date", "total_amount", "shipping_address_city"},
        "blocked_fields": {"credit_card_number", "ssn", "full_address", "date_of_birth"}
    },
    "account_lookup": {
        "allowed_fields": {"account_id", "username", "account_status", "plan_type"},
        "blocked_fields": {"password_hash", "ssn", "credit_card_number", "security_questions"}
    }
}

def field_level_filter(task_context: str):
    """
    Decorator that strips sensitive fields from tool return values
    based on the current task context.
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs) -> dict:
            raw_result = func(*args, **kwargs)
            schema = DATA_SCHEMAS.get(task_context)
            if not schema or not isinstance(raw_result, dict):
                return raw_result

            allowed = schema["allowed_fields"]
            filtered = {
                key: value
                for key, value in raw_result.items()
                if key in allowed
            }
            # Log any blocked fields that were present (for audit)
            blocked_present = set(raw_result.keys()) & schema["blocked_fields"]
            if blocked_present:
                import logging
                logging.getLogger("data_access_audit").warning(
                    f"Blocked fields stripped before agent context: {blocked_present} "
                    f"in task '{task_context}' for function '{func.__name__}'"
                )
            return filtered
        return wrapper
    return decorator


