import boto3
import os
from functools import lru_cache
from typing import Callable
import json
import logging

logger = logging.getLogger(__name__)


@lru_cache(maxsize=32)
def get_secret(secret_name: str, region: str = "us-east-1") -> dict:
    """
    Retrieve credentials from AWS Secrets Manager.
    Cached to avoid repeated API calls within a session.
    Never expose the return value to the agent context.
    """
    client = boto3.client("secretsmanager", region_name=region)
    response = client.get_secret_value(SecretId=secret_name)
    return json.loads(response["SecretString"])


def secure_tool(secret_name: str):
    """
    Decorator that injects credentials at execution time
    without exposing them to the agent's context window.
    The agent calls the tool with business parameters only;
    credentials are resolved internally.
    """
    def decorator(func: Callable):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Resolve credentials at call time, not at agent planning time
            try:
                credentials = get_secret(secret_name)
            except Exception as e:
                logger.error(f"Failed to retrieve secret '{secret_name}': {e}")
                raise RuntimeError("Tool authentication failed. Please try again.")

            # Pass credentials as internal kwargs, never visible to the LLM
            kwargs["_credentials"] = credentials
            return func(*args, **kwargs)
        return wrapper
    return decorator


